INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7ef64aa3-ffe6-4803-80ec-c18ac05a6d33',
  '00000000-0000-0000-0000-000000000001',
  $escape$Arbitrum Optimistic Rollups: Fraud Proofs, Challenge Period, and Withdrawal Delay$escape$,
  $escape$Arbitrum's Optimistic Rollups rely on fraud proofs to ensure the integrity of transactions. A fraud proof is generated when a malicious actor attempts to alter a previous transaction. This proof is submitted to the Optimism L2 network, which then triggers a challenge period. During this period, other validators can review the proof and verify its validity. If the proof is deemed valid, the transaction is reverted, and the attacker's stake is forfeited. However, if no challenge is submitted within the challenge period (currently set to 7 days on Arbitrum), the transaction is considered final, and the funds are withdrawn. To account for any potential delays, Arbitrum introduces a withdrawal delay of 7 days.$escape$,
  NULL,
  NULL,
