INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2588b91d-829e-4bcc-a7b7-65072f6f73cb',
  '00000000-0000-0000-0000-000000000001',
  $escape$Arbitrum Transaction Lifecycle: Mempool, Ordering, Finality, and Reorg Risk$escape$,
  $escape$On Arbitrum, a transaction is first submitted to the mempool, where it's validated and batched with other transactions. The batch is then ordered using the Optimistic Rollup protocol's ' optimistic' ordering mechanism. Once a batch is finalized, it's committed to the underlying Ethereum blockchain. However, if a reorg occurs on Ethereum, Arbitrum's finality gadget ensures that only the most recent state is maintained. This is achieved through a combination of the Optimistic Rollup's 'finalized' flag and the Ethereum blockchain's 'receipt' data.$escape$,
  NULL,
  NULL,
